@namespace sv_e3bdefa2eab5431581c73ba12df89249.Components.Pages.Apply

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")"
                @onclick="() => { if (isClickable) OnStepClicked.InvokeAsync(step); }"
                role="@(isClickable ? "button" : "")"
                style="cursor: @(isClickable ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                    @(isCurrent ? "bg-primary text-white" : "") @(isCompleted ? "bg-success text-white" : "")">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="@(isCurrent ? "fw-bold text-primary" : "") @(!isCurrent && !isCompleted ? "text-muted" : "")">
                    @StepNames[i]
                </small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator ol {
    counter-reset: step;
}

.step-circle {
    width: 36px;
    height: 36px;
    border: 2px solid #dee2e6;
    font-size: 0.875rem;
    font-weight: 600;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: var(--bs-primary);
}

.step-item.completed .step-circle {
    border-color: var(--bs-success);
}

.step-item.dimmed .step-circle {
    opacity: 0.5;
}

.step-item.completed:hover .step-circle {
    transform: scale(1.1);
}

@namespace sv_e3bdefa2eab5431581c73ba12df89249.Components.Pages.Apply
@using sv_e3bdefa2eab5431581c73ba12df89249.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
